import { redirect } from "next/navigation";
import { getSession } from "@/lib/session";
import CartPage from "../../../components/product/cartpage";

export default async function Cart() {
  const session = await getSession();

  if (!session?.user) {
    redirect("/login");
  }

  return (
    <div className="mt-40">
      <CartPage />
    </div>
  );
}
